                            let hPct = kind === 'text' ? 18 : 28;
                            let xPct = ((e.clientX - sr.left) / sr.width) * 100 - wPct / 2;
                            let yPct = ((e.clientY - sr.top) / sr.height) * 100 - hPct / 2;
                            modulesArr.push({ id: uid(), type: kind, xPct: xPct, yPct: yPct, wPct: wPct, hPct: hPct, html: kind === 'text' ? '<div><br></div>' : '', imgSrc: '' });
