                            item.doubleSided = !!window.lbBPDoubleSided;
                            item.blueprintModules = (window.lbCollectBPModules ? window.lbCollectBPModules() : []).filter(function(m) { return m.type !== 'alignLine'; });
                            item.paper = window.lbBPNoPaper ? '10' : (window.lbBPPaper || curPaper);
