                        <button type="button" class="dc-cmd" data-cmd="justifyRight" style="width:36px; height:34px; background:#26262e; color:#fff; border:1px solid #3a3a44; border-radius:5px; cursor:pointer;"><i class="fas fa-align-right"></i></button>
