            function lbOpenActorFileEditorFromItem(item) {
                if (!item || item.type !== 'actor-file') return;
                lbOpenActorFileEditor(foundry.utils.deepClone(item), {
                    theme: theme,
                    themeColor: themeColor,
                    themeColorRgb: themeColorRgb,
                    store: store,
                    saveStore: saveStore,
                    checkPerm: checkPerm,
                    generateCursorPreview: generateCursorPreview,
                    lbPaperPickerHTML: lbPaperPickerHTML,
                    lbBindPaperPicker: lbBindPaperPicker,
                    lbFontOptionsHTML: lbFontOptionsHTML,
                    lbEditorAttachPreviewSetup: lbEditorAttachPreviewSetup,
                    _editItemId: item.id
                });
            }

            window.lbTriggerActorFileReveal = function(itemId, revealType, revealName, ctx) {
                if (game.user.isGM) {
                    window.lbRunActorFileRevealCinematic(itemId, revealType, revealName, { remote: false, ctx: ctx, gmGate: true });
                } else {
                    window.lbRunActorFileRevealCinematic(itemId, revealType, revealName, { remote: false, ctx: ctx });
                }
            };

            window.lbBroadcastActorFileReveal = function(itemId, revealType, revealName) {
                let syncAt = Date.now() + 80;
                try {
                    game.socket.emit('module.loreboard', {
                        type: 'triggerReveal',
                        itemId: itemId,
                        revealType: revealType,
                        revealName: revealName || null,
                        syncAt: syncAt,
                        fromGM: true,
                        userId: game.user.id,
                        sceneId: storageEntity.id
                    });
                } catch (e) {}
            };

            function lbAfRevealFinishFlyback(clone, pEl, rect) {
                // Whatever path ends the reveal, the spin loop must never keep playing.
                lbStopSound('paperspin');
                clone.css({
                    transition: 'left 0.7s cubic-bezier(0.25,1,0.5,1), top 0.7s cubic-bezier(0.25,1,0.5,1), width 0.7s ease, height 0.7s ease, transform 0.7s cubic-bezier(0.25,1,0.5,1), opacity 0.4s ease',
                    left: rect.left + rect.width / 2 + 'px', top: rect.top + rect.height / 2 + 'px',
                    width: rect.width + 'px', height: rect.height + 'px',
                    transform: 'translate(-50%,-50%) scale(1) rotateY(0deg)', opacity: 0.1
                });
                setTimeout(function() {
                    clone.remove();
                    $('#lb-af-reveal-blocker, #lb-af-reveal-stage, #lb-af-reveal-end-btn').remove();
                    $(pEl).css('opacity', '1');
                    window.lbRevealPlaying = false;
                    if (typeof window.loadBoard === 'function') window.loadBoard(false);
                }, 720);
            }

            function lbAfRevealShowEndGate(itemId, revealType, revealName, clone, pEl, rect, applyRevealState) {
                $('#lb-af-reveal-end-btn').remove();
                if (!game.user.isGM) {
                    lbAfRevealFinishFlyback(clone, pEl, rect);
                    return;
                }
                let btn = $(`<button type="button" id="lb-af-reveal-end-btn"><i class="fas fa-check"></i> End Reveal</button>`);
                $('body').append(btn);
                btn.on('click', function() {
                    btn.prop('disabled', true).css('opacity', '0.6');
                    applyRevealState();
                    saveStore();
                    window.lbBroadcastActorFileReveal(itemId, revealType, revealName);
                    btn.remove();
                    lbAfRevealFinishFlyback(clone, pEl, rect);
                });
            }

            window.lbRunActorFileRevealCinematic = function(itemId, revealType, revealName, ctx) {
                ctx = ctx || {};
                let isRemote = !!ctx.remote;
                let gmGate = !!ctx.gmGate && game.user.isGM && !isRemote;
                let item = store.items.find(i => i.id === itemId);
                let pEl = document.getElementById(itemId);
                if (!item || !pEl) return;
                // Dedup: the same reveal arriving twice within a few seconds (double click,
                // echoed socket event) must not restart the cinematic and its sounds.
                let revealKey = itemId + ':' + revealType;
                if (window._lbLastRevealKey === revealKey && Date.now() - (window._lbLastRevealAt || 0) < 4000) return;
                window._lbLastRevealKey = revealKey;
                window._lbLastRevealAt = Date.now();
                window.lbRevealPlaying = true;
                window.lbRevealPlayingAt = Date.now();
                // Re-trigger safety: a previous reveal's pending timers must not stop THIS
                // run's spin sound or tear down its clone mid-flight.
                (window.lbAfRevealTimers || []).forEach(clearTimeout);
                window.lbAfRevealTimers = [];
                lbStopSound('paperspin');
                let rect = pEl.getBoundingClientRect();
                $('#lb-af-reveal-blocker, #lb-af-reveal-stage, #lb-af-reveal-end-btn').remove();
                $('body').append('<div id="lb-af-reveal-blocker"></div><div id="lb-af-reveal-stage"></div>');
                let cw = Math.min(rect.width * 1.5, window.innerWidth * 0.78);
                let ch = Math.min(rect.height * 1.5, window.innerHeight * 0.85);
                let clone = $(pEl).clone();
                clone.attr('id', 'lb-af-reveal-clone').addClass('lb-af-reveal-clone');
                if (revealType === 'name') clone.addClass('lb-af-reveal-name-only');
                clone.css({
                    left: '50%', top: '50%', width: cw + 'px', height: ch + 'px', margin: 0,
                    transform: 'translate(-50%,-50%) scale(1.4) rotateY(0deg)',
                    transition: 'none', filter: 'none'
                });
                $('#lb-af-reveal-stage').append(clone);
                $(pEl).css('opacity', '0');
                let showPhoto = revealType === 'photo' || revealType === 'complete';
                let showName = revealType === 'name' || revealType === 'complete';
                let realImg = item.defaultImg || item.realImg || item.img || '';
                let spinMs = 1500; // keep in sync with the lb-af-reveal-spinning animation duration
                let swapMs = Math.round(spinMs * 0.5);
                if (showPhoto && realImg && revealType !== 'name') {
                    clone.find('.lb-af-photo').first().append(`<img class="lb-af-reveal-photo" src="${realImg}" style="filter:${item.filter || lbBuildImgFilterAdj(item)};">`);
                }
                let applyRevealState = () => {
                    lbActorFileApplyReveal(item, revealType, revealName);
                    if (revealName) item.revealName = revealName;
                    if (showPhoto && realImg) item.img = item.defaultImg || realImg;
                    if (!isRemote && !gmGate) saveStore();
                };
                if (revealType === 'name') {
                    let nameEl = clone.find('.lb-af-namestrip text, .lb-af-fullprint-name text').first()[0];
                    let finalName = revealName || item.revealName || item.realName || item.name || '';
                    clone.addClass('lb-af-reveal-vibrate');
                    setTimeout(function() {
                        clone.removeClass('lb-af-reveal-vibrate');
                        lbTypewriterText(nameEl, finalName, 130, function() {
                            lbPlaySound('reveal');
                            if (gmGate) {
                                lbAfRevealShowEndGate(itemId, revealType, revealName, clone, pEl, rect, applyRevealState);
                            } else {
                                applyRevealState();
                                setTimeout(function() { lbAfRevealFinishFlyback(clone, pEl, rect); }, 400);
                            }
                        });
                    }, 650);
                    return;
                }
                lbPlaySound('paperspin', { loop: true, volume: 0.48 });
                clone.addClass('lb-af-reveal-spinning');
                requestAnimationFrame(function() {
                    window.lbAfRevealTimers.push(setTimeout(function() {
                        if (showPhoto && realImg) clone.find('.lb-af-reveal-photo').css('opacity', '1');
                        if (showName) {
                            let nameEl = clone.find('.lb-af-namestrip text, .lb-af-fullprint-name text').first();
                            let finalName = revealName || item.revealName || item.realName || item.name || '';
                            if (nameEl.length) nameEl.text(finalName);
                        }
                        if (!gmGate) applyRevealState();
                    }, swapMs));
                    window.lbAfRevealTimers.push(setTimeout(function() {
                        // Spin ends: stop the spin loop and fire the reveal sound at this exact moment.
                        lbStopSound('paperspin');
                        clone.removeClass('lb-af-reveal-spinning').addClass('lb-af-reveal-show');
                        lbPlaySound('reveal');
                    }, spinMs));
                    window.lbAfRevealTimers.push(setTimeout(function() {
                        if (gmGate) {
                            lbAfRevealShowEndGate(itemId, revealType, revealName, clone, pEl, rect, applyRevealState);
                        } else {
                            lbAfRevealFinishFlyback(clone, pEl, rect);
                        }
                    }, spinMs + 1000));
                });
            };

