                            let resizeToFit = () => { try { let a = dHtml[0].closest('.app'); if (a) { a.style.height = 'auto'; } } catch(e){} };
                            cb.on('change', () => { opts.css('display', cb.is(':checked') ? 'flex' : 'none'); resizeToFit(); });
