            let draggingItem = null; let resizingItem = null;
            let isDraggingPin = false; let connectingFrom = null;
            let pOffset = { startX: 0, startY: 0, startLeft: 0, startTop: 0 };
            let startW, startH, startX, startY;
            let isPanning = false; let panStartX = 0, panStartY = 0;
            let isDrawingPen = false; let currentDrawPath = []; let livePoly = null;
            let isErasing = false;
            // Eraser radius in board units. The on-screen preview circle is exactly this size, and erasing
            // happens within it, so the preview matches the real effect 1:1. (Doubled visible area.)
            let lbEraserRadius = 26;
            let midpinHoldTimer = null;
            let draggingMidpinId = null;
            // Right-click-hold reposition of an attached pin/tape (constrained to the item graphic).
            let attachHoldTimer = null;
            let draggingAttachId = null;
