                        let cy = Math.max(vy0, Math.min(vy1, e.clientY));
                        let sx = Math.max(vx0, Math.min(vx1, boundsStartX));
                        let sy = Math.max(vy0, Math.min(vy1, boundsStartY));
                        let w = Math.abs(cx - sx);
