                                let rx = Math.abs(currentDrawPath[0].x - pt.x)/2; let ry = Math.abs(currentDrawPath[0].y - pt.y)/2;
                                livePoly.setAttribute('cx', cx); livePoly.setAttribute('cy', cy);
