                        let startX = (startRect.left - tlRect.left + startRect.width/2) / boardZoom; let startY = (startRect.top - tlRect.top + startRect.height/2) / boardZoom;
                        let endX = (e.clientX - tlRect.left) / boardZoom; let endY = (e.clientY - tlRect.top) / boardZoom;
                        $('#lb-temp-thread').attr('d', `M ${startX} ${startY} Q ${(startX+endX)/2} ${(startY+endY)/2 + Math.hypot(endX-startX, endY-startY)*0.15} ${endX} ${endY}`);
                        if (window.lbEmitStoreLive) window.lbEmitStoreLive('tempThread', { from: connectingFrom, toX: e.clientX, toY: e.clientY });
